p.m:
\displaystyle{\begin{aligned}
   {\frac{\frac{4}{t}-\frac{8}{x}}{\frac{20}{t}+\frac{4}{x}}} 
      \amp = {\frac{\frac{4}{t}-\frac{8}{x}}{\frac{20}{t}+\frac{4}{x}}} \cdot \frac{{tx}}{{tx}} \\
      \amp = {\frac{\left(\frac{4}{t}-\frac{8}{x}\right)tx}{\left(\frac{20}{t}+\frac{4}{x}\right)tx}} \\
      \amp = \frac{\frac{4}{t} \cdot t x  -\frac{8}{x} \cdot t x }{\frac{20}{t} \cdot t x +\frac{4}{x} \cdot t x } \\
      \amp = \frac{4 x - 8 t}{20 x + 4 t} \\
      \amp = {\frac{4\mathopen{}\left(x-2t\right)}{4\mathopen{}\left(5x+t\right)}} \\
      \amp = {\frac{x-2t}{5x+t}}
\end{aligned}
    }
